@startuml
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor Black
  ArrowColor Black
}
skinparam stereotypeCBackgroundColor #D3D3D3
skinparam stereotypeCBorderColor Black
skinparam stereotypeABackgroundColor #ADD8E6
skinparam stereotypeABorderColor Black
skinparam stereotypeIBackgroundColor #D8BFD8
skinparam stereotypeIBorderColor Black

class Capitan {
  + nombre: String
  + apellido: String
  + matricula: int
  + Capitan(nombre String, apellido String, matricula int): void
}

class Embarcacion <<abstract>> {
  + capitan: Capitan
  + precioBase: double
  + valorAdicional: double
  + AñoDeFabricacion: int
  + montoDeAlquiler(): double
}

class Yate {
  + cantCamarotes: int
  + compareTo(o Object): int
}

class Velero {
  + cantMastiles: int
  + esGrande(): boolean
}

interface Comparable {
  + compareTo(o Object): int
}

Capitan "1" -- "1" Embarcacion
Embarcacion <|-- Yate : extends
Embarcacion <|-- Velero : extends
Yate ..|> Comparable : implements
@enduml
